Since I am an AI text model, I cannot directly generate a binary 3D file (like an `.obj` or `.fbx`) that you can download. However, I can provide you with the **complete code** to render a 3D house in your browser right now using **Three.js**.

This is the industry standard for 3D on the web. The code below creates a procedural house (walls, roof, door, windows) without needing to download external assets.

### How to use this:
1.  Create a new file on your computer named `house.html`.
2.  Paste the code below into that file.
3.  Open `house.html` in any modern web browser (Chrome, Firefox, Safari).

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Render</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click & Drag to Rotate | Scroll to Zoom</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. SCENE SETUP
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true; // Enable shadows
        document.body.appendChild(renderer.domElement);

        // 2. CONTROLS
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.target.set(0, 2, 0);

        // 3. LIGHTING
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. MATERIALS
        const wallMat = new THREE.MeshStandardMaterial({ color: 0xE0E0E0 }); // White walls
        const roofMat = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown roof
        const doorMat = new THREE.MeshStandardMaterial({ color: 0x4a3c31 }); // Dark wood
        const windowMat = new THREE.MeshStandardMaterial({ color: 0x88ccff, transparent: true, opacity: 0.6 });
        const grassMat = new THREE.MeshStandardMaterial({ color: 0x4caf50 });

        // 5. BUILDING THE HOUSE
        const houseGroup = new THREE.Group();

        // Floor
        const floorGeo = new THREE.BoxGeometry(10, 1, 8);
        const floor = new THREE.Mesh(floorGeo, grassMat);
        floor.position.y = 0;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // Main Body
        const bodyGeo = new THREE.BoxGeometry(8, 4, 6);
        const body = new THREE.Mesh(bodyGeo, wallMat);
        body.position.y = 2;
        body.castShadow = true;
        body.receiveShadow = true;
        houseGroup.add(body);

        // Roof (Pyramid)
        const roofGeo = new THREE.ConeGeometry(7, 3, 4);
        const roof = new THREE.Mesh(roofGeo, roofMat);
        roof.position.y = 5.5;
        roof.rotation.y = Math.PI / 4; // Rotate to align with walls
        roof.castShadow = true;
        houseGroup.add(roof);

        // Door
        const doorGeo = new THREE.BoxGeometry(1.5, 2.5, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMat);
        door.position.set(0, 1.25, 3.1); // Front center
        door.castShadow = true;
        houseGroup.add(door);

        // Windows (Simple squares)
        const winGeo = new THREE.BoxGeometry(1.5, 1.5, 0.1);

        // Front Window
        const win1 = new THREE.Mesh(winGeo, windowMat);
        win1.position.set(0, 2.5, 3.1);
        houseGroup.add(win1);

        // Side Window
        const win2 = new THREE.Mesh(winGeo, windowMat);
        win2.position.set(3.1, 2.5, 0);
        houseGroup.add(win2);

        // Chimney
        const chimGeo = new THREE.BoxGeometry(1, 2, 1);
        const chimney = new THREE.Mesh(chimGeo, wallMat);
        chimney.position.set(3, 6, 0);
        chimney.castShadow = true;
        houseGroup.add(chimney);

        scene.add(houseGroup);

        // 6. ANIMATION LOOP
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle window resize
        window.addEventListener('resize', onWindowResize, false);
        function onWindowResize() {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        }

        animate();
    </script>
</body>
</html>
```

### What this code does:
1.  **Setup:** Initializes a 3D scene, camera, and renderer.
2.  **Lighting:** Adds a directional light (simulating the sun) to create realistic shadows and an ambient light to fill in dark areas.
3.  **Geometry:**
    *   **Body:** A white box.
    *   **Roof:** A cone rotated 45 degrees to look like a pyramid roof.
    *   **Details:** Adds a door, two windows, and a chimney using smaller boxes.
4.  **Interaction:** Includes `OrbitControls`, allowing you to click and drag to rotate around the house and scroll to zoom in/out.
